#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, Q;
        scanf("%d %d %d", &N, &K, &Q);
        char S[N + 1];
        scanf("%s", S);
        while (Q--) {
            int L, R;
            scanf("%d %d", &L, &R);
            int count = 0;
            for (int i = L - 1; i < R; i++) {
                for (int j = i + 1; j <= R; j++) {
                    int zeros = 0, ones = 0;
                    for (int k = i; k < j; k++) {
                        if (S[k] == '0') zeros++;
                        else ones++;
                    }
                    if (zeros <= K && ones <= K) count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

