import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int Q = sc.nextInt();
            String S = sc.next();
            while (Q-- > 0) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int count = 0;
                for (int i = L - 1; i < R; i++) {
                    for (int j = i + 1; j <= R; j++) {
                        int zeros = 0, ones = 0;
                        for (int k = i; k < j; k++) {
                            if (S.charAt(k) == '0') zeros++;
                            else ones++;
                        }
                        if (zeros <= K && ones <= K) count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

